#include <stdio.h>
int countPairs(int arr[], int n) {
    int cnt = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (arr[i] > 2 * arr[j]) cnt++;
        }
    }
    return cnt;
}

int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    printf("%d\n", countPairs(arr, n));
    return 0;
}

